func (m heartbeatMods) RandomResponseNotNull(f *faker.Faker) HeartbeatMod {
	return HeartbeatModFunc(func(_ context.Context, o *HeartbeatTemplate) {
		o.Response = func() null.Val[[]byte] {
			if f == nil {
				f = &defaultFaker
			}

			val := random___byte(f)
			return null.From(val)
		}
	})
}

func (m heartbeatMods) WithParentsCascading() HeartbeatMod {
	return HeartbeatModFunc(func(ctx context.Context, o *HeartbeatTemplate) {
		if isDone, _ := heartbeatWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = heartbeatWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewMonitorWithContext(ctx, MonitorMods.WithParentsCascading())
			m.WithMonitor(related).Apply(ctx, o)
		}
	})
}

func (m heartbeatMods) WithMonitor(rel *MonitorTemplate) HeartbeatMod {
	return HeartbeatModFunc(func(ctx context.Context, o *HeartbeatTemplate) {
		o.r.Monitor = &heartbeatRMonitorR{
			o: rel,
		}
	})
}

func (m heartbeatMods) WithNewMonitor(mods ...MonitorMod) HeartbeatMod {
	return HeartbeatModFunc(func(ctx context.Context, o *HeartbeatTemplate) {
		related := o.f.NewMonitorWithContext(ctx, mods...)

		m.WithMonitor(related).Apply(ctx, o)
	})
}

func (m heartbeatMods) WithExistingMonitor(em *models.Monitor) HeartbeatMod {
	return HeartbeatModFunc(func(ctx context.Context, o *HeartbeatTemplate) {
		o.r.Monitor = &heartbeatRMonitorR{
			o: o.f.FromExistingMonitor(em),
		}
	})
}

func (m heartbeatMods) WithoutMonitor() HeartbeatMod {
	return HeartbeatModFunc(func(ctx context.Context, o *HeartbeatTemplate) {
		o.r.Monitor = nil
	})
}
